    96→export async function aiFeatureExtractionStage(
    97→  email: EmailMessage,
    98→  session: ClassificationSession,
    99→  candidateCategories: Record<string, unknown>,
   100→  detectedAttributes: Record<string, unknown>,
   101→  config: AIFeatureExtractionConfig
   102→): Promise<FeatureExtractionResult> {
   103→  const startTime = Date.now();
   104→  let retryCount = 0;
   105→  let apiCallCount = 0;
   106→
   107→  // Validate inputs
   108→  validateInputs(email, session, config);
   109→
   110→  // Initialize OpenAI client
   111→  const openai = new OpenAI({
   112→    apiKey: config.openai.apiKey,
   113→  });
   114→
   115→  // Setup JSON schema validator (only used for legacy json_object mode)
   116→  const ajv = new Ajv();
   117→  const validateSchema = ajv.compile(config.featureExtractionSchema.schema);
   118→
   119→  // Retry loop for API calls
   120→  let lastError: Error | null = null;
   121→
   122→  while (retryCount < config.retryPolicy.maxRetries) {
   123→    try {
   124→      apiCallCount++;
   125→
   126→      // Prepare prompts with email content interpolation
   127→      const systemPrompt = config.prompts.systemPrompt.join('\n');
   128→      const userPrompt = interpolateUserPrompt(
   129→        config.prompts.userPrompt,
   130→        email,
   131→        candidateCategories,
   132→        detectedAttributes
   133→      );
   134→
   135→      // Prepare response format based on configuration
   136→      const responseFormat =
   137→        config.openai.responseFormat === 'json_schema'
   138→          ? {
   139→            type: 'json_schema' as const,
   140→            json_schema: {
   141→              name: config.featureExtractionSchema.name || 'feature_extraction',
   142→              description:
   143→                  config.featureExtractionSchema.description ||
   144→                  'Extract semantic features and category enhancements from email content',
   145→              schema: config.featureExtractionSchema.schema,
   146→              strict: config.featureExtractionSchema.strict ?? true,
   147→            },
   148→          }
   149→          : { type: 'json_object' as const }; // Backward compatibility
   150→
   151→      // Call OpenAI API with structured outputs
   152→      const response = await openai.chat.completions.create({
   153→        model: config.openai.model,
   154→        temperature: config.openai.temperature,
   155→        response_format: responseFormat,
   156→        messages: [
   157→          { role: 'system', content: systemPrompt },
   158→          { role: 'user', content: userPrompt },
   159→        ],
   160→      });
   161→
   162→      // Parse and validate response
   163→      const rawContent = response.choices[0].message.content;
   164→      if (!rawContent) {
   165→        throw new Error('Empty response from OpenAI');
   166→      }
   167→
   168→      let featureExtractionData: FeatureExtractionData;
   169→      try {
   170→        featureExtractionData = JSON.parse(rawContent);
   171→      } catch {
   172→        throw new Error('Invalid JSON response from OpenAI');
   173→      }
   174→
   175→      // Schema validation: For structured outputs, OpenAI enforces the schema.
   176→      // For backward compatibility with json_object mode, we still validate with AJV.
   177→      const validationErrors: string[] = [];
   178→      let validationPassed = true;
   179→
   180→      if (config.openai.responseFormat === 'json_object') {
   181→        // Only validate with AJV for legacy json_object mode
   182→        validationPassed = validateSchema(featureExtractionData);
   183→
   184→        if (!validationPassed && validateSchema.errors) {
   185→          for (const error of validateSchema.errors) {
   186→            validationErrors.push(`${error.instancePath} ${error.message}`);
   187→          }
   188→          throw new Error('Schema validation failed: ' + validationErrors.join(', '));
   189→        }
   190→      }
   191→      // For json_schema mode, OpenAI has already enforced the schema, so no additional validation needed
   192→
   193→      // Validate evidence grounding
   194→      const evidenceValidation = validateEvidenceGrounding(email, featureExtractionData);
   195→
   196→      // Success - return result
   197→      return {
   198→        featureExtraction: featureExtractionData,
   199→        validationPassed: true,
   200→        validationErrors: [],
   201→        evidenceValidation,
   202→        processingDurationMs: Date.now() - startTime,
   203→        tokenUsage: response.usage?.total_tokens || 0,
   204→        apiCallCount,
   205→        retryCount,
   206→      };
   207→    } catch (error) {
   208→      lastError = error as Error;
   209→      retryCount++;
   210→
   211→      if (retryCount < config.retryPolicy.maxRetries) {
   212→        // Wait before retry with exponential backoff
   213→        await new Promise((resolve) => setTimeout(resolve, config.retryPolicy.backoffMs * Math.pow(2, retryCount - 1)));
   214→      }
   215→    }
   216→  }
   217→
   218→  // All retries exhausted
   219→  throw new Error(`AI feature extraction failed after ${config.retryPolicy.maxRetries} retries: ${lastError?.message}`);
   220→}
