   241→  }
   242→
   243→  if (!config.openai?.apiKey || config.openai.apiKey.trim() === '') {
   244→    throw new Error('Invalid configuration: OpenAI API key is required');
   245→  }
   246→
   247→  if (!config.prompts?.systemPrompt || !config.prompts?.userPrompt) {
   248→    throw new Error('Invalid configuration: system and user prompts are required');
   249→  }
   250→
   251→  if (!config.featureExtractionSchema) {
   252→    throw new Error('Invalid configuration: feature extraction schema is required');
   253→  }
   254→}
   255→
   256→/**
   257→ * Interpolate user prompt template with email content and analysis data
   258→ *
   259→ * Supports dynamic object path resolution with these placeholders:
   260→ * - {email.from} - formatted email address
   261→ * - {email.subject} - email subject
   262→ * - {email.body} - email body text
   263→ * - {candidateCategories} - JSON formatted candidate categories
   264→ * - {detectedAttributes} - JSON formatted detected attributes
   265→ */
   266→function interpolateUserPrompt(
   267→  userPromptTemplate: string[],
   268→  email: EmailMessage,
   269→  candidateCategories: Record<string, unknown>,
   270→  detectedAttributes: Record<string, unknown>
   271→): string {
   272→  const template = userPromptTemplate.join('\n');
   273→
   274→  // Create interpolation context with all available data
   275→  const context = {
   276→    email: {
   277→      from: formatEmailAddress(email.from),
   278→      subject: email.subject || '',
   279→      body: getEmailBodyText(email),
   280→    },
   281→    candidateCategories: formatObjectForTemplate(candidateCategories),
   282→    detectedAttributes: formatObjectForTemplate(detectedAttributes),
   283→  };
   284→
   285→  // Perform template interpolation using dynamic path resolution
   286→  return interpolateTemplate(template, context);
   287→}
   288→
   289→/**
   290→ * Format email address for prompt display
   291→ */
   292→function formatEmailAddress(address: unknown): string {
   293→  if (!address) return 'Unknown';
   294→
   295→  if (typeof address === 'string') return address;
   296→
   297→  if (typeof address === 'object' && address !== null) {
   298→    const addr = address as Record<string, string>;
   299→    if (addr.name && addr.email) {
   300→      return `${addr.name} <${addr.email}>`;
   301→    }
   302→    return addr.email || addr.raw || 'Unknown';
   303→  }
   304→
   305→  return 'Unknown';
   306→}
   307→
   308→/**
   309→ * Extract email body text (prefer plain text, fallback to HTML with improved stripping)
   310→ */
   311→function getEmailBodyText(email: EmailMessage): string {
   312→  if (email.bodyPlain) {
   313→    return email.bodyPlain;
   314→  }
   315→
   316→  if (email.bodyHtml) {
   317→    // Improved HTML stripping with better performance and safety
   318→    return email.bodyHtml
   319→      .replace(/<script[^>]*>.*?<\/script>/gi, '') // Remove script blocks
   320→      .replace(/<style[^>]*>.*?<\/style>/gi, '') // Remove style blocks
   321→      .replace(/<[^>]*>/g, '') // Remove HTML tags
   322→      .replace(/&[#A-Za-z0-9]+;/g, ' ') // Remove HTML entities
   323→      .replace(/\s+/g, ' ') // Normalize whitespace
   324→      .trim();
   325→  }
   326→
   327→  return '[No body content available]';
   328→}
   329→
   330→// Template object size limits (in characters)
   331→const TEMPLATE_SIZE_LIMITS = {
   332→  PRETTY_PRINT_LIMIT: 10000, // Use pretty printing below this size
   333→  COMPACT_FORMAT_LIMIT: 15000, // Use compact format below this size
   334→  MAX_TEMPLATE_SIZE: 20000, // Truncate above this size
   335→} as const;
   336→
   337→/**
   338→ * Check if an object contains null/empty values that would benefit from compaction
   339→ * Includes depth limits to prevent excessive recursion
   340→ */
   341→function hasCompactableContent(obj: Record<string, unknown>, maxDepth = 10): boolean {
   342→  if (maxDepth <= 0) return false; // Prevent deep recursion
   343→
   344→  for (const value of Object.values(obj)) {
   345→    if (value === null || value === undefined) return true;
   346→    if (Array.isArray(value) && value.length === 0) return true;
   347→    if (typeof value === 'object' && value !== null) {
   348→      const objValue = value as Record<string, unknown>;
   349→      if (Object.keys(objValue).length === 0) return true;
   350→      if (hasCompactableContent(objValue, maxDepth - 1)) return true;
   351→    }
   352→  }
   353→  return false;
   354→}
   355→
   356→/**
   357→ * Format an object for template inclusion with progressive compaction
   358→ *
   359→ * Progressive approach:
   360→ * 1. Check if compaction would be beneficial (has nulls/empties)
   361→ * 2. If beneficial, apply compaction first
   362→ * 3. Choose format based on size: pretty -> compact -> minified -> truncated
   363→ * Optimized to minimize JSON.stringify() calls for better performance
   364→ */
   365→function formatObjectForTemplate(obj: Record<string, unknown>): string {
   366→  const startTime = Date.now();
   367→  let originalSize: number | undefined;
   368→
   369→  try {
   370→    // Step 1: Determine if we should compact (has null/empty values)
   371→    const shouldCompact = hasCompactableContent(obj);
   372→    const objectToFormat = shouldCompact ? createCompactedObject(obj) : obj;
   373→
   374→    // Step 2: Calculate compact JSON first (smallest computation)
   375→    const compactJson = JSON.stringify(objectToFormat);
   376→
   377→    // Add memory usage warning for large objects
   378→    if (compactJson.length > 100000) {
   379→      // 100KB threshold
   380→      console.warn(`Large object detected (${compactJson.length} chars). Consider processing in smaller chunks.`);
   381→    }
   382→
   383→    // Step 3: Choose format based on compact size (avoiding additional stringify calls)
   384→    if (compactJson.length <= TEMPLATE_SIZE_LIMITS.PRETTY_PRINT_LIMIT) {
   385→      // Only calculate pretty JSON if compact format would fit in pretty limit
   386→      const prettyJson = JSON.stringify(objectToFormat, null, 2);
   387→      return prettyJson;
   388→    }
   389→
   390→    if (compactJson.length <= TEMPLATE_SIZE_LIMITS.COMPACT_FORMAT_LIMIT) {
   391→      return compactJson;
   392→    }
   393→
   394→    // Step 4: Try minified version without extra spaces
   395→    const minifiedJson = compactJson.replace(/\s+/g, ' ').trim();
   396→    if (minifiedJson.length <= TEMPLATE_SIZE_LIMITS.MAX_TEMPLATE_SIZE) {
   397→      return minifiedJson;
   398→    }
   399→
   400→    // Step 5: Truncate with ellipsis and log warning
   401→    // Only calculate original size if we need it for error logging
   402→    originalSize = shouldCompact ? JSON.stringify(obj).length : compactJson.length;
   403→    const truncated = minifiedJson.substring(0, TEMPLATE_SIZE_LIMITS.MAX_TEMPLATE_SIZE - 50) + '...[truncated]';
   404→
   405→    const processingTime = Date.now() - startTime;
   406→    console.warn(
   407→      `Object too large for template after compaction. Original: ${originalSize} chars, ` +
   408→        `Compacted: ${compactJson.length} chars, Truncated to: ${truncated.length} chars, ` +
   409→        `Processing time: ${processingTime}ms`
   410→    );
   411→    return '[Object too large for template - see logs for details]';
   412→  } catch (error) {
   413→    const processingTime = Date.now() - startTime;
   414→    console.warn('Object formatting error:', {
   415→      error: error instanceof Error ? error.message : 'Unknown error',
   416→      originalSize: originalSize || 'unknown',
   417→      processingTime: `${processingTime}ms`,
   418→    });
   419→    return '[Object formatting error]';
   420→  }
   421→}
   422→
   423→/**
   424→ * Create a deeply compacted version of an object by removing nulls, empties recursively
   425→ * with protection against circular references and stack overflow
   426→ */
   427→function createCompactedObject(obj: Record<string, unknown>): Record<string, unknown> {
   428→  const seen = new WeakSet<object>();
   429→  const result = compactValue(obj, seen, 0);
   430→  return (result as Record<string, unknown>) || {};
   431→}
   432→
   433→/**
   434→ * Recursively compact a single value with circular reference detection and depth limits
   435→ */
   436→function compactValue(value: unknown, seen = new WeakSet<object>(), depth = 0): unknown {
   437→  const MAX_DEPTH = 10; // Much more conservative depth limit
   438→
   439→  if (depth > MAX_DEPTH) {
   440→    console.warn(`Object nesting too deep (>${MAX_DEPTH} levels), stopping compaction`);
   441→    return undefined; // Remove deeply nested content to prevent issues
   442→  }
   443→
   444→  if (value === null || value === undefined) {
   445→    return undefined;
   446→  }
   447→
   448→  if (Array.isArray(value)) {
   449→    if (seen.has(value)) {
   450→      return '[Circular Reference]'; // Prevent infinite loops
   451→    }
   452→    seen.add(value);
   453→
   454→    const compactedArray = value
   455→      .map((item) => compactValue(item, seen, depth + 1))
   456→      .filter((item) => item !== undefined);
   457→
   458→    seen.delete(value); // Clean up for other branches
   459→    return compactedArray.length > 0 ? compactedArray : undefined;
   460→  }
   461→
   462→  if (typeof value === 'object' && value !== null) {
   463→    if (seen.has(value)) {
   464→      return '[Circular Reference]'; // Prevent infinite loops
   465→    }
   466→    seen.add(value);
   467→
   468→    const compactedObj: Record<string, unknown> = {};
   469→    let hasValidProperties = false;
   470→
   471→    for (const [key, val] of Object.entries(value)) {
   472→      const compactedVal = compactValue(val, seen, depth + 1);
   473→      if (compactedVal !== undefined) {
   474→        compactedObj[key] = compactedVal;
   475→        hasValidProperties = true;
   476→      }
   477→    }
   478→
   479→    seen.delete(value); // Clean up for other branches
   480→    return hasValidProperties ? compactedObj : undefined;
   481→  }
   482→
   483→  return value;
   484→}
   485→
   486→/**
   487→ * Template interpolation engine with dynamic path resolution and security safeguards
   488→ *
   489→ * Supports placeholders like {object.property} and {simpleProperty}
   490→ * Prevents template injection by sanitizing paths and output values
   491→ */
   492→function interpolateTemplate(template: string, context: Record<string, unknown>): string {
   493→  return template.replace(/{([^}]+)}/g, (match, path) => {
   494→    // Sanitize path to prevent injection - only allow alphanumeric, dots, and underscores
   495→    if (!/^[a-zA-Z][a-zA-Z0-9._]*$/.test(path)) {
   496→      return match; // Reject suspicious paths
   497→    }
   498→
   499→    try {
   500→      const pathParts = path.split('.');
   501→      let value: unknown = context;
   502→
   503→      for (const part of pathParts) {
   504→        if (value && typeof value === 'object' && value !== null && part in value) {
   505→          value = (value as Record<string, unknown>)[part];
   506→        } else {
   507→          return match; // Keep original placeholder if path not found
   508→        }
   509→      }
   510→
   511→      // Type-safe string conversion with output sanitization
   512→      if (typeof value === 'string') {
   513→        // Sanitize output to prevent prompt injection by escaping template characters
   514→        return sanitizeTemplateOutput(value);
   515→      } else if (typeof value === 'number' || typeof value === 'boolean') {
   516→        return String(value);
   517→      } else if (value != null) {
   518→        return sanitizeTemplateOutput(String(value));
   519→      } else {
   520→        return match; // Keep original placeholder if null/undefined
   521→      }
   522→    } catch {
   523→      // If path resolution fails, keep original placeholder
   524→      return match;
   525→    }
   526→  });
   527→}
   528→
   529→/**
   530→ * Sanitize template output to prevent injection attacks
   531→ *
   532→ * Enhanced security with robust JSON detection and aggressive sanitization
   533→ */
   534→function sanitizeTemplateOutput(value: string): string {
   535→  // More robust JSON detection to prevent bypass attacks
   536→  const looksLikeJson = (() => {
   537→    try {
   538→      JSON.parse(value);
   539→      return true; // Valid JSON
   540→    } catch {
   541→      // Fallback heuristic for JSON-like strings
   542→      const trimmed = value.trim();
   543→      return (
   544→        trimmed.startsWith('{') &&
   545→        trimmed.endsWith('}') &&
   546→        trimmed.includes(':') &&
   547→        trimmed.includes('"') &&
   548→        !trimmed.includes('{{') // Avoid false positives with nested braces
   549→      );
   550→    }
   551→  })();
   552→
   553→  if (looksLikeJson) {
   554→    // For JSON, only normalize whitespace but preserve structure
   555→    return value
   556→      .replace(/[\n\r\t]/g, ' ')
   557→      .replace(/\s+/g, ' ')
   558→      .trim();
   559→  } else {
   560→    // For plain text, aggressively sanitize all template-like patterns
   561→    return value
   562→      .replace(/\{+([^}]*)\}+/g, '[$1]') // Handle multiple braces: {{evil}} -> [evil]
   563→      .replace(/[\n\r\t]/g, ' ') // Normalize all whitespace characters
   564→      .replace(/\s+/g, ' ') // Collapse multiple spaces
   565→      .trim();
   566→  }
   567→}
   568→
   569→/**
   570→ * Validate that quoted phrases in evidence actually exist in the email content
   571→ */
   572→function validateEvidenceGrounding(email: EmailMessage, featureExtraction: FeatureExtractionData): EvidenceValidation {
   573→  const emailText = (email.subject + ' ' + getEmailBodyText(email)).toLowerCase();
   574→  const validPhrases: string[] = [];
   575→  const invalidPhrases: string[] = [];
   576→
   577→  // Check all quoted phrases in category enhancements
   578→  for (const [, enhancement] of Object.entries(featureExtraction.category_enhancements || {})) {
   579→    if (enhancement.evidence?.quoted_phrases) {
   580→      for (const phrase of enhancement.evidence.quoted_phrases) {
   581→        const normalizedPhrase = phrase.toLowerCase().trim();
   582→        if (normalizedPhrase && emailText.includes(normalizedPhrase)) {
   583→          validPhrases.push(phrase);
   584→        } else if (normalizedPhrase) {
   585→          invalidPhrases.push(phrase);
   586→        }
   587→      }
   588→    }
   589→  }
   590→
   591→  return {
   592→    validPhrases,
   593→    invalidPhrases,
   594→    fabricationDetected: invalidPhrases.length > 0,
   595→  };
   596→}
