 *  2. Identify AI-related stages: ai_feature_extraction, ai_classification
 *  3. Generate stage completion summaries for both AI stages
 *  4. Mark stages as "skipped" with detailed rationale
 *  5. Set weight_score to 0 and passed_to_next to true
 *  6. Prepare data for stage completion persistence
 *
 * OUTPUT FORMAT
 *  Enhanced email objects with AI stage completion summaries:
 *  [{
 *    gmail_id: string,
 *    session_id: string,
 *    stage_summaries: [{
 *      stage_id: string,               // AI feature extraction stage ID
 *      stage_type: "ai_feature_extraction",
 *      weight_score: 0,
 *      rationale: "Skipped: AI processing not required (route_to_ai=false)",
 *      passed_to_next: true
 *    }, {
 *      stage_id: string,               // AI classification stage ID
 *      stage_type: "ai_classification",
 *      weight_score: 0,
 *      rationale: "Skipped: AI processing not required (route_to_ai=false)",
 *      passed_to_next: true
 *    }],
 *    // ... all original email data preserved
 *  }]
 *
 * ARCHITECTURAL IMPORTANCE
 *  This node ensures complete stage completion tracking for all emails regardless
 *  of whether they use AI processing, maintaining consistent audit trails and
 *  enabling accurate pipeline performance analysis.
 */

const CodeNode = require('../../../../n8n-simulator/src/nodes/CodeNode');

class MarkSkippedAIStagesNode extends CodeNode {
  constructor() {
    super('MarkSkippedAIStages');
  }

  async execute($input) {
    const inputItems = $input.all();
    console.log('Starting mark_skipped_ai_stages node execution');
    console.log(`Processing ${inputItems.length} emails that skipped AI processing`);

    const processedItems = [];

    for (const item of inputItems) {
      const data = item.json;

      // Verify this email was correctly routed away from AI
      if (data.needs_ai_classification === true) {
        console.warn(`Warning: Email ${data.gmail_id} has needs_ai_classification=true but was routed to skip branch`);
      }

      // Get stage IDs for AI stages that need to be marked as skipped
      const stageIds = data.stage_ids || {};
      const aiFeatureExtractionStageId = stageIds.ai_feature_extraction;
      const aiClassificationStageId = stageIds.ai_classification;

      const stageSummaries = [];
      const skipRationale = 'Skipped: AI processing not required (route_to_ai=false based on confidence thresholds)';

      // Mark AI Feature Extraction stage as skipped
      if (aiFeatureExtractionStageId) {
        stageSummaries.push({
          stage_id: aiFeatureExtractionStageId,
          stage_type: 'ai_feature_extraction',
          weight_score: 0, // No score for skipped stages
          rationale: skipRationale,
          passed_to_next: true, // Passed to final decision
        });
        console.log(
          `Marked AI feature extraction stage ${aiFeatureExtractionStageId} as skipped for email ${data.gmail_id}`
        );
      }

      // Mark AI Classification stage as skipped
      if (aiClassificationStageId) {
        stageSummaries.push({
          stage_id: aiClassificationStageId,
          stage_type: 'ai_classification',
          weight_score: 0, // No score for skipped stages
          rationale: skipRationale,
          passed_to_next: true, // Passed to final decision
        });
        console.log(`Marked AI classification stage ${aiClassificationStageId} as skipped for email ${data.gmail_id}`);
      }

      // Create processed item with stage summaries for database completion
      processedItems.push({
        json: {
          ...data,
          stage_summaries: stageSummaries,
          skipped_ai_stages: true,
          skip_reason: 'Confidence thresholds met without AI assistance',
        },
      });
    }

    console.log(
      `Processed ${processedItems.length} emails with ${processedItems.reduce((sum, item) => sum + item.json.stage_summaries.length, 0)} skipped AI stages`
    );
    return processedItems;
  }
}

module.exports = MarkSkippedAIStagesNode;

