/**
 * AI Classification Stage
 *
 * Stage 8b of the EmailCategorizer pipeline. Final AI classification using enhanced features
 * from T035a with candidate scores and extracted features, including skip handling for
 * high-confidence direct routing.
 *
 * This stage is responsible for:
 * - Combining rule-based candidate scores with AI-extracted feature enhancements
 * - Making final multi-label classification decisions using OpenAI GPT-4o-mini
 * - Implementing skip logic for high-confidence scenarios
 * - Providing complete explainability traces with decision rationale
 * - Supporting both json_schema and json_object response formats for backward compatibility
 */

import { OpenAI } from 'openai';
import { EmailMessage, ClassificationSession } from '../types';
import { FeatureExtractionData } from './ai-feature-extraction';

// Configuration interface for AI classification
export interface AIClassificationConfig {
  openai: {
    apiKey: string;
    model: string;
    temperature: number;
    responseFormat: 'json_schema' | 'json_object';
  };
  prompts: {
    systemPrompt: string[];
    userPrompt: string[];
  };
  classificationSchema: {
    name?: string;
    description?: string;
    schema: Record<string, unknown>;
    strict?: boolean;
  };
  skipConditions: {
    highConfidenceThreshold: number;
    skipReasons: string[];
  };
  retryPolicy: {
    maxRetries: number;
    backoffMs: number;
  };
}

// Final classification decision from AI
export interface FinalClassification {
  primary_category: string;
  secondary_categories: string[];
  confidence: number;
  reasoning: string;
  category_scores?: Record<string, number>;
}

// Enhancement calculation for explainability
export interface EnhancementCalculation {
  category: string;
  originalScore: number;
  confidenceBoost: number;
  enhancedScore: number;
  boostReason: string;
}

// AI routing decision details
export interface AIRoutingDecision {
  routedToAI: boolean;
  reason: string;
  confidenceScore?: number;
  threshold?: number;
  skipConditionsEvaluated: string[];
  decisionRationale: string;
}

// API usage tracking
export interface APIUsage {
  totalTokens: number;
  promptTokens?: number;
  completionTokens?: number;
}

// Complete explainability trace for the AI classification stage
export interface AIClassificationExplainabilityTrace {
  candidateScoresInput: Record<string, number>;
  extractedFeaturesInput: FeatureExtractionData;
  enhancementCalculations: EnhancementCalculation[];
  aiRoutingDecision: AIRoutingDecision;
  finalDecisionRationale: string;
  apiUsage?: APIUsage;
  processingSteps: string[];
}

// Complete stage result interface
export interface AIClassificationResult {
  finalClassification: FinalClassification;
  enhancedScores: Record<string, number>;
  aiInvoked: boolean;
  skipped: boolean;
  skipReason?: string;
  processingDurationMs: number;
  tokenUsage: number;
  apiCallCount: number;
  retryCount: number;
  validationErrors: string[];
  explainabilityTrace: AIClassificationExplainabilityTrace;
}

/**
 * AI Classification Stage Implementation
 *
 * Combines rule-based candidate scores with AI-extracted features to make final
 * multi-label classification decisions, with intelligent skip handling for
 * high-confidence scenarios.
 */
export async function aiClassificationStage(
  email: EmailMessage,
  session: ClassificationSession,
  candidateCategories: Record<string, number>,
  extractedFeatures: FeatureExtractionData,
  config: AIClassificationConfig
): Promise<AIClassificationResult> {
  const startTime = Date.now();
  let retryCount = 0;
  let apiCallCount = 0;
  let tokenUsage = 0;
  const validationErrors: string[] = [];
  const processingSteps: string[] = [];

  // Validate inputs
  validateInputs(email, session, candidateCategories, extractedFeatures, config);
  processingSteps.push('Input validation completed');

  // Calculate enhanced scores by applying feature confidence boosts
  const enhancementCalculations: EnhancementCalculation[] = [];
  const enhancedScores = calculateEnhancedScores(
    candidateCategories,
    extractedFeatures,
    enhancementCalculations,
    validationErrors
  );
  processingSteps.push(`Enhanced scores calculated for ${Object.keys(enhancedScores).length} categories`);

  // Evaluate skip conditions
  const aiRoutingDecision = evaluateSkipConditions(enhancedScores, extractedFeatures, config);
  processingSteps.push(`Skip conditions evaluated: ${aiRoutingDecision.reason}`);

  // Initialize explainability trace
  const explainabilityTrace: AIClassificationExplainabilityTrace = {
    candidateScoresInput: { ...candidateCategories },
    extractedFeaturesInput: { ...extractedFeatures },
    enhancementCalculations,
    aiRoutingDecision,
    finalDecisionRationale: '',
    processingSteps,
  };

  // Handle skip scenarios
  if (!aiRoutingDecision.routedToAI) {
    const finalClassification = createDirectClassification(enhancedScores, aiRoutingDecision.reason);
    explainabilityTrace.finalDecisionRationale = `Direct classification based on ${aiRoutingDecision.reason}`;

    return {
      finalClassification,
      enhancedScores,
      aiInvoked: false,
      skipped: true,
      skipReason: aiRoutingDecision.reason,
      processingDurationMs: Date.now() - startTime,
      tokenUsage: 0,
      apiCallCount: 0,
      retryCount: 0,
      validationErrors,
      explainabilityTrace,
    };
  }

  // Proceed with AI classification
  processingSteps.push('Proceeding with AI classification');

  // Initialize OpenAI client
  const openai = new OpenAI({
    apiKey: config.openai.apiKey,
  });

  // Retry loop for AI API calls
  let lastError: Error | null = null;

  while (retryCount < config.retryPolicy.maxRetries) {
    try {
      apiCallCount++;
      processingSteps.push(`AI API call attempt ${apiCallCount}`);

      // Prepare prompts with enhanced scores and features
      const systemPrompt = config.prompts.systemPrompt.join('\n');
      const userPrompt = interpolateClassificationPrompt(
        config.prompts.userPrompt,
        email,
        enhancedScores,
        extractedFeatures
      );

      // Prepare response format based on configuration
      const responseFormat =
        config.openai.responseFormat === 'json_schema'
          ? {
            type: 'json_schema' as const,
            json_schema: {
              name: config.classificationSchema.name || 'final_classification',
              description: config.classificationSchema.description || 'Final multi-label email classification',
              schema: config.classificationSchema.schema,
              strict: config.classificationSchema.strict ?? true,
            },
          }
          : { type: 'json_object' as const }; // Backward compatibility

      // Call OpenAI API
      const response = await openai.chat.completions.create({
        model: config.openai.model,
        temperature: config.openai.temperature,
        response_format: responseFormat,
        messages: [
          { role: 'system', content: systemPrompt },
          { role: 'user', content: userPrompt },
        ],
      });

      // Parse and validate response
      const rawContent = response.choices[0].message.content;
      if (!rawContent) {
        throw new Error('Empty response from OpenAI');
      }

      let finalClassification: FinalClassification;
      try {
        finalClassification = JSON.parse(rawContent);
      } catch {
        throw new Error('Invalid JSON response from OpenAI');
      }

      // Track API usage
      tokenUsage = response.usage?.total_tokens || 0;
      explainabilityTrace.apiUsage = {
        totalTokens: response.usage?.total_tokens || 0,
        promptTokens: response.usage?.prompt_tokens,
        completionTokens: response.usage?.completion_tokens,
      };

      // Validate AI response structure
      validateAIResponse(finalClassification, config);

      explainabilityTrace.finalDecisionRationale = `AI classification completed: ${finalClassification.reasoning}`;
      processingSteps.push('AI classification successful');

      // Success - return result
      return {
        finalClassification,
        enhancedScores,
        aiInvoked: true,
        skipped: false,
        processingDurationMs: Date.now() - startTime,
        tokenUsage,
        apiCallCount,
        retryCount,
        validationErrors,
        explainabilityTrace,
      };
    } catch (error) {
      lastError = error as Error;
      retryCount++;
      processingSteps.push(`AI API call failed (attempt ${apiCallCount}): ${lastError.message}`);

      if (retryCount < config.retryPolicy.maxRetries) {
        // Wait before retry with exponential backoff
        const backoffMs = config.retryPolicy.backoffMs * Math.pow(2, retryCount - 1);
        await new Promise((resolve) => setTimeout(resolve, backoffMs));
        processingSteps.push(`Retrying after ${backoffMs}ms backoff`);
      }
    }
  }

  // All retries exhausted
  throw new Error(`AI classification failed after ${config.retryPolicy.maxRetries} retries: ${lastError?.message}`);
}

/**
 * Validate input parameters
 */
function validateInputs(
  email: EmailMessage,
  session: ClassificationSession,
  candidateCategories: Record<string, number>,
  extractedFeatures: FeatureExtractionData,
  config: AIClassificationConfig
): void {
  if (!email || (!email.id && !('gmail_id' in email))) {
    throw new Error('Invalid email input: id or gmail_id is required');
  }

  if (!session || (!session.id && !('session_id' in session))) {
    throw new Error('Invalid session input: id or session_id is required');
  }

  if (!candidateCategories || typeof candidateCategories !== 'object') {
    throw new Error('Invalid candidate categories: object with numeric scores required');
  }

  if (!extractedFeatures || typeof extractedFeatures !== 'object') {
    throw new Error('Invalid extracted features: feature extraction data required');
  }

  if (!config) {
    throw new Error('Configuration is required');
  }

  if (!config.openai?.apiKey || config.openai.apiKey.trim() === '') {
    throw new Error('Invalid configuration: OpenAI API key is required');
  }

  if (!config.prompts?.systemPrompt || !config.prompts?.userPrompt) {
    throw new Error('Invalid configuration: system and user prompts are required');
  }

  if (!config.classificationSchema?.schema) {
    throw new Error('Invalid configuration: classification schema is required');
  }
}

/**
 * Calculate enhanced scores by applying AI feature confidence boosts
 */
function calculateEnhancedScores(
  candidateCategories: Record<string, number>,
  extractedFeatures: FeatureExtractionData,
  enhancementCalculations: EnhancementCalculation[],
  validationErrors: string[]
): Record<string, number> {
  const enhancedScores: Record<string, number> = {};

  // Validate extracted features format
  if (!extractedFeatures.semantic_intent || !extractedFeatures.category_enhancements) {
    validationErrors.push('Invalid extracted features format');
    // Fallback to original scores without enhancement
    return { ...candidateCategories };
  }

  for (const [category, originalScore] of Object.entries(candidateCategories)) {
    let enhancedScore = originalScore;
    let confidenceBoost = 0;
    let boostReason = 'No feature enhancement';

    // Apply AI feature enhancement if available
    const categoryEnhancement = extractedFeatures.category_enhancements?.[category];
    if (categoryEnhancement) {
      confidenceBoost = categoryEnhancement.confidence_boost || 0;

      // Apply positive boosts only when category applies, but apply negative boosts regardless
      if (categoryEnhancement.applies || confidenceBoost < 0) {
        enhancedScore = originalScore + originalScore * confidenceBoost;
        boostReason = `Applied ${confidenceBoost > 0 ? 'positive' : 'negative'} confidence boost based on AI features`;
      }
    }

    enhancedScores[category] = enhancedScore;

    // Track enhancement calculation for explainability
    enhancementCalculations.push({
      category,
      originalScore,
      confidenceBoost,
      enhancedScore,
      boostReason,
    });
  }

  return enhancedScores;
}

/**
 * Evaluate skip conditions to determine if AI classification should be bypassed
 */
function evaluateSkipConditions(
  enhancedScores: Record<string, number>,
  extractedFeatures: FeatureExtractionData,
  config: AIClassificationConfig
): AIRoutingDecision {
  const skipConditionsEvaluated: string[] = [];

  // Find highest scoring category
  const maxScore = Math.max(...Object.values(enhancedScores));
  const highestCategory = Object.entries(enhancedScores).find(([, score]) => score === maxScore)?.[0];

  // Check high confidence threshold
  skipConditionsEvaluated.push('high_confidence_threshold');
  if (maxScore >= config.skipConditions.highConfidenceThreshold) {
    return {
      routedToAI: false,
      reason: 'high_confidence',
      confidenceScore: maxScore,
      threshold: config.skipConditions.highConfidenceThreshold,
      skipConditionsEvaluated,
      decisionRationale: `Highest category score (${maxScore}) exceeds high confidence threshold (${config.skipConditions.highConfidenceThreshold})`,
    };
  }

  // Check for hard assertion condition
  if (config.skipConditions.skipReasons.includes('hard_assertion')) {
    skipConditionsEvaluated.push('hard_assertion');
    if ((extractedFeatures as any).hard_assertion_detected) {
      return {
        routedToAI: false,
        reason: 'hard_assertion',
        skipConditionsEvaluated,
        decisionRationale: 'Hard assertion detected in earlier pipeline stage',
      };
    }
  }

  // Default: route to AI
  return {
    routedToAI: true,
    reason: 'requires_ai_classification',
    skipConditionsEvaluated,
    decisionRationale: `Confidence scores require AI classification (max: ${maxScore}, threshold: ${config.skipConditions.highConfidenceThreshold})`,
  };
}

/**
 * Create direct classification result when AI is skipped
 */
function createDirectClassification(enhancedScores: Record<string, number>, skipReason: string): FinalClassification {
  // Sort categories by score descending
  const sortedCategories = Object.entries(enhancedScores)
    .sort(([, a], [, b]) => b - a)
    .filter(([, score]) => score > 0);

  if (sortedCategories.length === 0) {
    return {
      primary_category: 'unclassified',
      secondary_categories: [],
      confidence: 0.5,
      reasoning: `No categories scored above 0. Skip reason: ${skipReason}`,
      category_scores: enhancedScores,
    };
  }

  const primaryCategory = sortedCategories[0][0];
  const primaryScore = sortedCategories[0][1];

  // Determine secondary categories (score > 3 and not primary)
  const secondaryCategories = sortedCategories
    .slice(1)
    .filter(([, score]) => score > 3)
    .map(([category]) => category);

  // Calculate confidence based on score magnitude and separation
  const confidence = Math.min(0.95, Math.max(0.5, primaryScore / 20));

  return {
    primary_category: primaryCategory,
    secondary_categories: secondaryCategories,
    confidence,
    reasoning: `Direct classification: ${skipReason}. Primary category "${primaryCategory}" scored ${primaryScore.toFixed(2)}`,
    category_scores: enhancedScores,
  };
}

/**
 * Interpolate classification prompt template with enhanced scores and extracted features
 *
 * Reuses template interpolation utilities from ai-feature-extraction.ts
 */
function interpolateClassificationPrompt(
  userPromptTemplate: string[],
  email: EmailMessage,
  enhancedScores: Record<string, number>,
  extractedFeatures: FeatureExtractionData
): string {
  const template = userPromptTemplate.join('\n');

  // Create interpolation context with all available data
  const context = {
    email: {
      from: formatEmailAddress(email.from),
      subject: email.subject || '',
      body: getEmailBodyText(email),
    },
    candidateCategories: formatObjectForTemplate(enhancedScores),
    extractedFeatures: formatObjectForTemplate(extractedFeatures),
  };

  // Perform template interpolation using dynamic path resolution
  return interpolateTemplate(template, context);
}

/**
 * Validate AI response structure matches expected schema
 */
function validateAIResponse(response: any, config: AIClassificationConfig): void {
  if (!response || typeof response !== 'object') {
    throw new Error('AI response must be an object');
  }

  if (!response.primary_category || typeof response.primary_category !== 'string') {
    throw new Error('AI response must include primary_category as string');
  }

  if (
    response.confidence !== undefined &&
    (typeof response.confidence !== 'number' || response.confidence < 0 || response.confidence > 1)
  ) {
    throw new Error('AI response confidence must be a number between 0 and 1');
  }

  if (response.secondary_categories !== undefined && !Array.isArray(response.secondary_categories)) {
    throw new Error('AI response secondary_categories must be an array');
  }
}

// === Utility Functions (Reused from ai-feature-extraction.ts) ===

/**
 * Format email address for prompt display
 */
function formatEmailAddress(address: unknown): string {
  if (!address) return 'Unknown';

  if (typeof address === 'string') return address;

  if (typeof address === 'object' && address !== null) {
    const addr = address as Record<string, string>;
    if (addr.name && addr.email) {
      return `${addr.name} <${addr.email}>`;
    }
    return addr.email || addr.raw || 'Unknown';
  }

  return 'Unknown';
}

/**
 * Extract email body text (prefer plain text, fallback to HTML with improved stripping)
 */
function getEmailBodyText(email: EmailMessage): string {
  if (email.bodyPlain) {
    return email.bodyPlain;
  }

  if (email.bodyHtml) {
    // Improved HTML stripping with better performance and safety
    return email.bodyHtml
      .replace(/<script[^>]*>.*?<\/script>/gi, '') // Remove script blocks
      .replace(/<style[^>]*>.*?<\/style>/gi, '') // Remove style blocks
      .replace(/<[^>]*>/g, '') // Remove HTML tags
      .replace(/&[#A-Za-z0-9]+;/g, ' ') // Remove HTML entities
      .replace(/\s+/g, ' ') // Normalize whitespace
      .trim();
  }

  return '[No body content available]';
}

/**
 * Format an object for template inclusion with progressive compaction
 * (Reused from ai-feature-extraction.ts)
 */
function formatObjectForTemplate(obj: Record<string, unknown>): string {
  try {
    // Simple formatting for classification prompts - use compact JSON
    const compactJson = JSON.stringify(obj);

    if (compactJson.length <= 10000) {
      // Use pretty format for smaller objects
      return JSON.stringify(obj, null, 2);
    } else {
      // Use compact format for larger objects
      return compactJson;
    }
  } catch (error) {
    console.warn('Object formatting error:', error);
    return '[Object formatting error]';
  }
}

/**
 * Template interpolation engine with dynamic path resolution
 * (Reused from ai-feature-extraction.ts)
 */
function interpolateTemplate(template: string, context: Record<string, unknown>): string {
  return template.replace(/{([^}]+)}/g, (match, path) => {
    // Sanitize path to prevent injection - only allow alphanumeric, dots, and underscores
    if (!/^[a-zA-Z][a-zA-Z0-9._]*$/.test(path)) {
      return match; // Reject suspicious paths
    }

    try {
      const pathParts = path.split('.');
      let value: unknown = context;

      for (const part of pathParts) {
        if (value && typeof value === 'object' && value !== null && part in value) {
          value = (value as Record<string, unknown>)[part];
        } else {
          return match; // Keep original placeholder if path not found
        }
      }

      // Type-safe string conversion with output sanitization
      if (typeof value === 'string') {
        return sanitizeTemplateOutput(value);
      } else if (typeof value === 'number' || typeof value === 'boolean') {
        return String(value);
      } else if (value != null) {
        return sanitizeTemplateOutput(String(value));
      } else {
        return match; // Keep original placeholder if null/undefined
      }
    } catch {
      // If path resolution fails, keep original placeholder
      return match;
    }
  });
}

/**
 * Sanitize template output to prevent injection attacks
 * (Reused from ai-feature-extraction.ts)
 */
function sanitizeTemplateOutput(value: string): string {
  // For classification prompts, normalize whitespace but preserve structure
  return value
    .replace(/[\n\r\t]/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();
}

