   300→  if (!session || (!session.id && !('session_id' in session))) {
   301→    throw new Error('Invalid session input: id or session_id is required');
   302→  }
   303→
   304→  if (!candidateCategories || typeof candidateCategories !== 'object') {
   305→    throw new Error('Invalid candidate categories: object with numeric scores required');
   306→  }
   307→
   308→  if (!extractedFeatures || typeof extractedFeatures !== 'object') {
   309→    throw new Error('Invalid extracted features: feature extraction data required');
   310→  }
   311→
   312→  if (!config) {
   313→    throw new Error('Configuration is required');
   314→  }
   315→
   316→  if (!config.openai?.apiKey || config.openai.apiKey.trim() === '') {
   317→    throw new Error('Invalid configuration: OpenAI API key is required');
   318→  }
   319→
   320→  if (!config.prompts?.systemPrompt || !config.prompts?.userPrompt) {
   321→    throw new Error('Invalid configuration: system and user prompts are required');
   322→  }
   323→
   324→  if (!config.classificationSchema?.schema) {
   325→    throw new Error('Invalid configuration: classification schema is required');
   326→  }
   327→}
   328→
   329→/**
   330→ * Calculate enhanced scores by applying AI feature confidence boosts
   331→ */
   332→function calculateEnhancedScores(
   333→  candidateCategories: Record<string, number>,
   334→  extractedFeatures: FeatureExtractionData,
   335→  enhancementCalculations: EnhancementCalculation[],
   336→  validationErrors: string[]
   337→): Record<string, number> {
   338→  const enhancedScores: Record<string, number> = {};
   339→
   340→  // Validate extracted features format
   341→  if (!extractedFeatures.semantic_intent || !extractedFeatures.category_enhancements) {
   342→    validationErrors.push('Invalid extracted features format');
   343→    // Fallback to original scores without enhancement
   344→    return { ...candidateCategories };
   345→  }
   346→
   347→  for (const [category, originalScore] of Object.entries(candidateCategories)) {
   348→    let enhancedScore = originalScore;
   349→    let confidenceBoost = 0;
   350→    let boostReason = 'No feature enhancement';
   351→
   352→    // Apply AI feature enhancement if available
   353→    const categoryEnhancement = extractedFeatures.category_enhancements?.[category];
   354→    if (categoryEnhancement) {
   355→      confidenceBoost = categoryEnhancement.confidence_boost || 0;
   356→
   357→      // Apply positive boosts only when category applies, but apply negative boosts regardless
   358→      if (categoryEnhancement.applies || confidenceBoost < 0) {
   359→        enhancedScore = originalScore + originalScore * confidenceBoost;
   360→        boostReason = `Applied ${confidenceBoost > 0 ? 'positive' : 'negative'} confidence boost based on AI features`;
   361→      }
   362→    }
   363→
   364→    enhancedScores[category] = enhancedScore;
   365→
   366→    // Track enhancement calculation for explainability
   367→    enhancementCalculations.push({
   368→      category,
   369→      originalScore,
   370→      confidenceBoost,
   371→      enhancedScore,
   372→      boostReason,
   373→    });
   374→  }
   375→
   376→  return enhancedScores;
   377→}
   378→
   379→/**
   380→ * Evaluate skip conditions to determine if AI classification should be bypassed
   381→ */
   382→function evaluateSkipConditions(
   383→  enhancedScores: Record<string, number>,
   384→  extractedFeatures: FeatureExtractionData,
   385→  config: AIClassificationConfig
   386→): AIRoutingDecision {
   387→  const skipConditionsEvaluated: string[] = [];
   388→
   389→  // Find highest scoring category
   390→  const maxScore = Math.max(...Object.values(enhancedScores));
   391→
   392→  // Check for hard assertion condition first (highest priority)
   393→  if (config.skipConditions.skipReasons.includes('hard_assertion')) {
   394→    skipConditionsEvaluated.push('hard_assertion');
   395→    if ((extractedFeatures as unknown as Record<string, unknown>).hard_assertion_detected) {
   396→      return {
   397→        routedToAI: false,
   398→        reason: 'hard_assertion',
   399→        skipConditionsEvaluated,
   400→        decisionRationale: 'Hard assertion detected in earlier pipeline stage',
   401→      };
   402→    }
   403→  }
   404→
   405→  // Check high confidence threshold
   406→  skipConditionsEvaluated.push('high_confidence_threshold');
   407→  if (maxScore >= config.skipConditions.highConfidenceThreshold) {
   408→    return {
   409→      routedToAI: false,
   410→      reason: 'high_confidence',
   411→      confidenceScore: maxScore,
   412→      threshold: config.skipConditions.highConfidenceThreshold,
   413→      skipConditionsEvaluated,
   414→      decisionRationale: `Highest category score (${maxScore}) exceeds high confidence threshold (${config.skipConditions.highConfidenceThreshold})`,
   415→    };
   416→  }
   417→
   418→  // Default: route to AI
   419→  return {
   420→    routedToAI: true,
   421→    reason: 'requires_ai_classification',
   422→    skipConditionsEvaluated,
   423→    decisionRationale: `Confidence scores require AI classification (max: ${maxScore}, threshold: ${config.skipConditions.highConfidenceThreshold})`,
   424→  };
   425→}
   426→
   427→/**
   428→ * Create direct classification result when AI is skipped
   429→ */
   430→function createDirectClassification(enhancedScores: Record<string, number>, skipReason: string): FinalClassification {
   431→  // Sort categories by score descending
   432→  const sortedCategories = Object.entries(enhancedScores)
   433→    .sort(([, a], [, b]) => b - a)
   434→    .filter(([, score]) => score > 0);
   435→
   436→  if (sortedCategories.length === 0) {
   437→    return {
   438→      primary_category: 'unclassified',
   439→      secondary_categories: [],
   440→      confidence: 0.5,
   441→      reasoning: `No categories scored above 0. Skip reason: ${skipReason}`,
   442→      category_scores: enhancedScores,
   443→    };
   444→  }
   445→
   446→  const primaryCategory = sortedCategories[0][0];
   447→  const primaryScore = sortedCategories[0][1];
   448→
   449→  // Determine secondary categories (score > 3 and not primary)
   450→  const secondaryCategories = sortedCategories
   451→    .slice(1)
   452→    .filter(([, score]) => score > 3)
   453→    .map(([category]) => category);
   454→
   455→  // Calculate confidence based on score magnitude and separation
   456→  const confidence = Math.min(0.95, Math.max(0.5, primaryScore / 20));
   457→
   458→  return {
   459→    primary_category: primaryCategory,
   460→    secondary_categories: secondaryCategories,
   461→    confidence,
   462→    reasoning: `Direct classification: ${skipReason}. Primary category "${primaryCategory}" scored ${primaryScore.toFixed(2)}`,
   463→    category_scores: enhancedScores,
   464→  };
   465→}
   466→
   467→/**
   468→ * Interpolate classification prompt template with enhanced scores and extracted features
   469→ *
   470→ * Reuses template interpolation utilities from ai-feature-extraction.ts
   471→ */
   472→function interpolateClassificationPrompt(
   473→  userPromptTemplate: string[],
   474→  email: EmailMessage,
   475→  enhancedScores: Record<string, number>,
   476→  extractedFeatures: FeatureExtractionData
   477→): string {
   478→  const template = userPromptTemplate.join('\n');
   479→
   480→  // Create interpolation context with all available data
   481→  const context = {
   482→    email: {
   483→      from: formatEmailAddress(email.from),
   484→      subject: email.subject || '',
   485→      body: getEmailBodyText(email),
   486→    },
   487→    candidateCategories: formatObjectForTemplate(enhancedScores),
   488→    extractedFeatures: formatObjectForTemplate(extractedFeatures as unknown as Record<string, unknown>),
   489→  };
   490→
   491→  // Perform template interpolation using dynamic path resolution
   492→  return interpolateTemplate(template, context);
   493→}
   494→
   495→/**
   496→ * Validate AI response structure matches expected schema
   497→ */
   498→function validateAIResponse(response: Record<string, unknown>): void {
   499→  if (!response || typeof response !== 'object') {
   500→    throw new Error('AI response must be an object');
   501→  }
   502→
   503→  if (!response.primary_category || typeof response.primary_category !== 'string') {
   504→    throw new Error('AI response must include primary_category as string');
   505→  }
   506→
   507→  if (
   508→    response.confidence !== undefined &&
   509→    (typeof response.confidence !== 'number' || response.confidence < 0 || response.confidence > 1)
   510→  ) {
   511→    throw new Error('AI response confidence must be a number between 0 and 1');
   512→  }
   513→
   514→  if (response.secondary_categories !== undefined && !Array.isArray(response.secondary_categories)) {
   515→    throw new Error('AI response secondary_categories must be an array');
   516→  }
   517→}
   518→
   519→// === Utility Functions (Reused from ai-feature-extraction.ts) ===
   520→
   521→/**
   522→ * Format email address for prompt display
   523→ */
   524→function formatEmailAddress(address: unknown): string {
   525→  if (!address) return 'Unknown';
   526→
   527→  if (typeof address === 'string') return address;
   528→
   529→  if (typeof address === 'object' && address !== null) {
   530→    const addr = address as Record<string, string>;
   531→    if (addr.name && addr.email) {
   532→      return `${addr.name} <${addr.email}>`;
   533→    }
   534→    return addr.email || addr.raw || 'Unknown';
   535→  }
   536→
   537→  return 'Unknown';
   538→}
   539→
   540→/**
   541→ * Extract email body text (prefer plain text, fallback to HTML with improved stripping)
   542→ */
   543→function getEmailBodyText(email: EmailMessage): string {
   544→  if (email.bodyPlain) {
   545→    return email.bodyPlain;
   546→  }
   547→
   548→  if (email.bodyHtml) {
   549→    // Improved HTML stripping with better performance and safety
   550→    return email.bodyHtml
   551→      .replace(/<script[^>]*>.*?<\/script>/gi, '') // Remove script blocks
   552→      .replace(/<style[^>]*>.*?<\/style>/gi, '') // Remove style blocks
   553→      .replace(/<[^>]*>/g, '') // Remove HTML tags
   554→      .replace(/&[#A-Za-z0-9]+;/g, ' ') // Remove HTML entities
   555→      .replace(/\s+/g, ' ') // Normalize whitespace
   556→      .trim();
   557→  }
   558→
   559→  return '[No body content available]';
   560→}
   561→
   562→/**
   563→ * Format an object for template inclusion with progressive compaction
   564→ * (Reused from ai-feature-extraction.ts)
   565→ */
   566→function formatObjectForTemplate(obj: Record<string, unknown>): string {
   567→  try {
   568→    // Simple formatting for classification prompts - use compact JSON
   569→    const compactJson = JSON.stringify(obj);
   570→
   571→    if (compactJson.length <= 10000) {
   572→      // Use pretty format for smaller objects
   573→      return JSON.stringify(obj, null, 2);
   574→    } else {
   575→      // Use compact format for larger objects
   576→      return compactJson;
   577→    }
   578→  } catch (error) {
   579→    console.warn('Object formatting error:', error);
   580→    return '[Object formatting error]';
   581→  }
   582→}
   583→
   584→/**
   585→ * Template interpolation engine with dynamic path resolution
   586→ * (Reused from ai-feature-extraction.ts)
   587→ */
   588→function interpolateTemplate(template: string, context: Record<string, unknown>): string {
   589→  return template.replace(/{([^}]+)}/g, (match, path) => {
   590→    // Sanitize path to prevent injection - only allow alphanumeric, dots, and underscores
   591→    if (!/^[a-zA-Z][a-zA-Z0-9._]*$/.test(path)) {
   592→      return match; // Reject suspicious paths
   593→    }
   594→
   595→    try {
   596→      const pathParts = path.split('.');
   597→      let value: unknown = context;
   598→
   599→      for (const part of pathParts) {
   600→        if (value && typeof value === 'object' && value !== null && part in value) {
   601→          value = (value as Record<string, unknown>)[part];
   602→        } else {
   603→          return match; // Keep original placeholder if path not found
   604→        }
   605→      }
   606→
   607→      // Type-safe string conversion with output sanitization
   608→      if (typeof value === 'string') {
   609→        return sanitizeTemplateOutput(value);
   610→      } else if (typeof value === 'number' || typeof value === 'boolean') {
   611→        return String(value);
   612→      } else if (value != null) {
   613→        return sanitizeTemplateOutput(String(value));
   614→      } else {
   615→        return match; // Keep original placeholder if null/undefined
   616→      }
   617→    } catch {
   618→      // If path resolution fails, keep original placeholder
   619→      return match;
   620→    }
   621→  });
   622→}
   623→
   624→/**
   625→ * Sanitize template output to prevent injection attacks
   626→ * (Reused from ai-feature-extraction.ts)
   627→ */
   628→function sanitizeTemplateOutput(value: string): string {
   629→  // For classification prompts, normalize whitespace but preserve structure
   630→  return value
   631→    .replace(/[\n\r\t]/g, ' ')
   632→    .replace(/\s+/g, ' ')
   633→    .trim();
   634→}
