/**
 * Template Utilities Unit Tests
 *
 * Comprehensive test coverage for shared template utility functions used by
 * both ai-feature-extraction.ts and ai-classification.ts stages.
 *
 * Test Coverage:
 * - Email address formatting
 * - Email body text extraction
 * - Object formatting with progressive compaction
 * - Template interpolation with security
 * - Output sanitization
 */

import {
  formatEmailAddress,
  getEmailBodyText,
  formatObjectForTemplate,
  interpolateTemplate,
} from '../../src/utils/template-utils';
import { EmailMessage } from '../../src/types';

describe('Template Utilities', () => {
  describe('formatEmailAddress', () => {
    it('should format email object with name and email', () => {
      const address = {
        name: 'John Doe',
        email: 'john@example.com',
        raw: 'John Doe <john@example.com>',
      };

      expect(formatEmailAddress(address)).toBe('John Doe <john@example.com>');
    });

    it('should format email object with only email', () => {
      const address = {
        email: 'john@example.com',
        raw: 'john@example.com',
      };

      expect(formatEmailAddress(address)).toBe('john@example.com');
    });

    it('should format email object with only raw', () => {
      const address = {
        raw: 'john@example.com',
      };

      expect(formatEmailAddress(address)).toBe('john@example.com');
    });

    it('should handle string input directly', () => {
      expect(formatEmailAddress('john@example.com')).toBe('john@example.com');
    });

    it('should handle null input', () => {
      expect(formatEmailAddress(null)).toBe('Unknown');
    });

    it('should handle undefined input', () => {
      expect(formatEmailAddress(undefined)).toBe('Unknown');
    });

    it('should handle empty object', () => {
      expect(formatEmailAddress({})).toBe('Unknown');
    });
  });

  describe('getEmailBodyText', () => {
    it('should prefer plain text body', () => {
      const email: EmailMessage = {
        id: 'test-1',
        threadId: 'thread-1',
        subject: 'Test',
        from: { email: 'test@example.com', raw: 'test@example.com' },
        date: new Date(),
        bodyPlain: 'Plain text content',
        bodyHtml: '<p>HTML content</p>',
        gmailLabels: [],
        payload: { mimeType: 'text/plain', headers: [] },
      };

      expect(getEmailBodyText(email)).toBe('Plain text content');
    });

    it('should strip HTML tags from bodyHtml', () => {
      const email: EmailMessage = {
        id: 'test-1',
        threadId: 'thread-1',
        subject: 'Test',
        from: { email: 'test@example.com', raw: 'test@example.com' },
        date: new Date(),
        bodyHtml: '<p>Hello <strong>World</strong></p>',
        gmailLabels: [],
        payload: { mimeType: 'text/html', headers: [] },
      };

      expect(getEmailBodyText(email)).toBe('Hello World');
    });

    it('should remove script tags', () => {
      const email: EmailMessage = {
        id: 'test-1',
        threadId: 'thread-1',
        subject: 'Test',
        from: { email: 'test@example.com', raw: 'test@example.com' },
        date: new Date(),
        bodyHtml: '<p>Content</p><script>alert("xss")</script><p>More</p>',
        gmailLabels: [],
        payload: { mimeType: 'text/html', headers: [] },
      };

      expect(getEmailBodyText(email)).toBe('ContentMore'); // Space removed during normalization
    });

    it('should remove style tags', () => {
      const email: EmailMessage = {
        id: 'test-1',
        threadId: 'thread-1',
        subject: 'Test',
        from: { email: 'test@example.com', raw: 'test@example.com' },
        date: new Date(),
        bodyHtml: '<style>.red{color:red}</style><p>Content</p>',
        gmailLabels: [],
        payload: { mimeType: 'text/html', headers: [] },
      };

      expect(getEmailBodyText(email)).toBe('Content');
    });

    it('should convert HTML entities to spaces', () => {
      const email: EmailMessage = {
        id: 'test-1',
        threadId: 'thread-1',
        subject: 'Test',
        from: { email: 'test@example.com', raw: 'test@example.com' },
        date: new Date(),
        bodyHtml: '<p>Test&nbsp;&amp;&lt;&gt;Content</p>',
        gmailLabels: [],
        payload: { mimeType: 'text/html', headers: [] },
      };

      expect(getEmailBodyText(email)).toBe('Test Content');
    });

    it('should normalize whitespace', () => {
      const email: EmailMessage = {
        id: 'test-1',
        threadId: 'thread-1',
        subject: 'Test',
        from: { email: 'test@example.com', raw: 'test@example.com' },
        date: new Date(),
        bodyHtml: '<p>Multiple   \n\n  spaces  \t  and   tabs</p>',
        gmailLabels: [],
        payload: { mimeType: 'text/html', headers: [] },
      };

      expect(getEmailBodyText(email)).toBe('Multiple spaces and tabs');
    });

    it('should handle missing body content', () => {
      const email: EmailMessage = {
        id: 'test-1',
        threadId: 'thread-1',
        subject: 'Test',
        from: { email: 'test@example.com', raw: 'test@example.com' },
        date: new Date(),
        gmailLabels: [],
        payload: { mimeType: 'text/plain', headers: [] },
      };

      expect(getEmailBodyText(email)).toBe('[No body content available]');
    });
  });

  describe('formatObjectForTemplate', () => {
    it('should use pretty format for small objects', () => {
      const obj = { name: 'test', value: 123 };
      const result = formatObjectForTemplate(obj);

      expect(result).toContain('\n'); // Pretty format has newlines
      expect(result).toContain('  '); // Pretty format has indentation
      expect(JSON.parse(result)).toEqual(obj);
    });

    it('should use compact format for medium objects', () => {
      // Create object that exceeds pretty print limit (10KB) but under compact limit (15KB)
      const largeArray = Array(500).fill({ key: 'value', number: 12345 });
      const obj = { data: largeArray };
      const result = formatObjectForTemplate(obj);

      expect(result).not.toContain('\n  '); // Compact format has no indentation
      expect(JSON.parse(result)).toEqual(obj);
    });

    it('should remove null values during compaction', () => {
      const obj = {
        valid: 'value',
        nullValue: null,
        undefinedValue: undefined,
        nested: {
          valid: 'nested',
          nullNested: null,
        },
      };

      const result = formatObjectForTemplate(obj);
      const parsed = JSON.parse(result);

      expect(parsed.valid).toBe('value');
      expect(parsed.nullValue).toBeUndefined();
      expect(parsed.undefinedValue).toBeUndefined();
      expect(parsed.nested.valid).toBe('nested');
      expect(parsed.nested.nullNested).toBeUndefined();
    });

    it('should remove empty arrays during compaction', () => {
      const obj = {
        validArray: [1, 2, 3],
        emptyArray: [],
        nested: {
          emptyNested: [],
        },
      };

      const result = formatObjectForTemplate(obj);
      const parsed = JSON.parse(result);

      expect(parsed.validArray).toEqual([1, 2, 3]);
      expect(parsed.emptyArray).toBeUndefined();
      expect(parsed.nested?.emptyNested).toBeUndefined();
    });

    it('should remove empty objects during compaction', () => {
      const obj = {
        validObject: { key: 'value' },
        emptyObject: {},
        nested: {
          emptyNested: {},
        },
      };

      const result = formatObjectForTemplate(obj);
      const parsed = JSON.parse(result);

      expect(parsed.validObject).toEqual({ key: 'value' });
      expect(parsed.emptyObject).toBeUndefined();
      expect(parsed.nested?.emptyNested).toBeUndefined();
    });

    it('should handle circular references gracefully', () => {
      const obj: Record<string, unknown> = { name: 'test' };
      obj.self = obj; // Create circular reference

      const result = formatObjectForTemplate(obj);

      expect(result).toBe('[Object formatting error]');
    });

    it('should handle deeply nested objects with depth limit', () => {
      const consoleSpy = jest.spyOn(console, 'warn').mockImplementation();

      // Create object nested beyond MAX_DEPTH (10 levels)
      let deepObj: Record<string, unknown> = { level: 15 };
      for (let i = 14; i >= 0; i--) {
        deepObj = { level: i, nested: deepObj };
      }

      const result = formatObjectForTemplate(deepObj);

      // Should warn about depth limit being exceeded
      expect(consoleSpy).toHaveBeenCalledWith(expect.stringContaining('Object nesting too deep'));

      const parsed = JSON.parse(result);

      // Deep nesting should be truncated during compaction
      // The compacted object should be shallower than the original
      let depth = 0;
      let current = parsed;
      while (current?.nested && depth < 20) {
        // Safety limit to prevent infinite loop
        depth++;
        current = current.nested;
      }

      // Depth should be limited by the compaction process
      expect(depth).toBeLessThanOrEqual(10);

      consoleSpy.mockRestore();
    });

    it('should warn about large objects', () => {
      const consoleSpy = jest.spyOn(console, 'warn').mockImplementation();

      // Create object > 100KB
      const largeArray = Array(5000).fill({
        key: 'value'.repeat(10),
        number: 123456789,
      });
      const obj = { data: largeArray };

      formatObjectForTemplate(obj);

      expect(consoleSpy).toHaveBeenCalledWith(expect.stringContaining('Large object detected'));

      consoleSpy.mockRestore();
    });

    it('should handle formatting errors gracefully', () => {
      const consoleSpy = jest.spyOn(console, 'warn').mockImplementation();

      // Create object that will cause JSON.stringify to fail
      const obj: Record<string, unknown> = {};
      Object.defineProperty(obj, 'bad', {
        get() {
          throw new Error('Getter error');
        },
        enumerable: true,
      });

      const result = formatObjectForTemplate(obj);

      expect(result).toBe('[Object formatting error]');
      expect(consoleSpy).toHaveBeenCalledWith('Object formatting error:', expect.any(Object));

      consoleSpy.mockRestore();
    });
  });

  describe('interpolateTemplate', () => {
    it('should replace simple placeholders', () => {
      const template = 'Hello {name}, you have {count} messages';
      const context = { name: 'John', count: 5 };

      expect(interpolateTemplate(template, context)).toBe('Hello John, you have 5 messages');
    });

    it('should replace nested placeholders', () => {
      const template = 'From: {email.from}, Subject: {email.subject}';
      const context = {
        email: {
          from: 'test@example.com',
          subject: 'Test Subject',
        },
      };

      expect(interpolateTemplate(template, context)).toBe('From: test@example.com, Subject: Test Subject');
    });

    it('should handle deeply nested paths', () => {
      const template = 'Value: {data.level1.level2.level3}';
      const context = {
        data: {
          level1: {
            level2: {
              level3: 'deep value',
            },
          },
        },
      };

      expect(interpolateTemplate(template, context)).toBe('Value: deep value');
    });

    it('should keep placeholder if path not found', () => {
      const template = 'Value: {missing.path}';
      const context = { other: 'value' };

      expect(interpolateTemplate(template, context)).toBe('Value: {missing.path}');
    });

    it('should reject suspicious paths with special characters', () => {
      const template = 'Value: {../../../etc/passwd}';
      const context = {};

      expect(interpolateTemplate(template, context)).toBe('Value: {../../../etc/passwd}');
    });

    it('should reject paths starting with numbers', () => {
      const template = 'Value: {123abc}';
      const context = {};

      expect(interpolateTemplate(template, context)).toBe('Value: {123abc}');
    });

    it('should allow paths with underscores', () => {
      const template = 'Value: {data.user_name}';
      const context = {
        data: {
          user_name: 'john_doe',
        },
      };

      expect(interpolateTemplate(template, context)).toBe('Value: john_doe');
    });

    it('should sanitize string output', () => {
      const template = 'Text: {text}';
      const context = {
        text: 'Line 1\nLine 2\t\tTabbed',
      };

      const result = interpolateTemplate(template, context);
      expect(result).toBe('Text: Line 1 Line 2 Tabbed');
      expect(result).not.toContain('\n');
      expect(result).not.toContain('\t');
    });

    it('should handle number values', () => {
      const template = 'Count: {count}';
      const context = { count: 42 };

      expect(interpolateTemplate(template, context)).toBe('Count: 42');
    });

    it('should handle boolean values', () => {
      const template = 'Active: {active}';
      const context = { active: true };

      expect(interpolateTemplate(template, context)).toBe('Active: true');
    });

    it('should keep placeholder for null values', () => {
      const template = 'Value: {nullValue}';
      const context = { nullValue: null };

      expect(interpolateTemplate(template, context)).toBe('Value: {nullValue}');
    });

    it('should keep placeholder for undefined values', () => {
      const template = 'Value: {undefinedValue}';
      const context = { undefinedValue: undefined };

      expect(interpolateTemplate(template, context)).toBe('Value: {undefinedValue}');
    });

    it('should handle multiple placeholders', () => {
      const template = '{greeting} {name}, your score is {score} out of {max}';
      const context = {
        greeting: 'Hello',
        name: 'Alice',
        score: 95,
        max: 100,
      };

      expect(interpolateTemplate(template, context)).toBe('Hello Alice, your score is 95 out of 100');
    });

    it('should handle path resolution errors gracefully', () => {
      const template = 'Value: {path.to.value}';
      const context = {
        path: {
          to: null, // Will cause error on property access
        },
      };

      expect(interpolateTemplate(template, context)).toBe('Value: {path.to.value}');
    });

    it('should handle objects as values by converting to string', () => {
      const template = 'Object: {obj}';
      const context = {
        obj: { key: 'value' },
      };

      const result = interpolateTemplate(template, context);
      expect(result).toContain('[object Object]');
    });

    it('should handle array values by converting to string', () => {
      const template = 'Array: {arr}';
      const context = {
        arr: [1, 2, 3],
      };

      const result = interpolateTemplate(template, context);
      expect(result).toBe('Array: 1,2,3');
    });
  });

  describe('Integration: Template Interpolation with Object Formatting', () => {
    it('should work together for complex email templates', () => {
      const template = [
        'From: {email.from}',
        'Subject: {email.subject}',
        'Body: {email.body}',
        '',
        'Candidate Categories:',
        '{candidateCategories}',
      ].join('\n');

      const context = {
        email: {
          from: 'John Doe <john@example.com>',
          subject: 'Test Email',
          body: 'This is the email body',
        },
        candidateCategories: formatObjectForTemplate({
          financial: 8.5,
          actionable: 4.2,
        }),
      };

      const result = interpolateTemplate(template, context);

      expect(result).toContain('From: John Doe <john@example.com>');
      expect(result).toContain('Subject: Test Email');
      expect(result).toContain('Body: This is the email body');
      expect(result).toContain('"financial": 8.5');
      expect(result).toContain('"actionable": 4.2');
    });
  });
});

