  // Helper function to create large objects for testing
  function createLargeObject(targetSize: number): Record<string, unknown> {
    const baseObject: Record<string, unknown> = {};
    let currentSize = 0;
    let counter = 0;

    while (currentSize < targetSize) {
      const data = `large_data_item_${counter}_${'x'.repeat(100)}`;
      baseObject[`field_${counter}`] = data;
      currentSize = JSON.stringify(baseObject).length;
      counter++;
    }

    return baseObject;
  }

