/**
 * Unit Tests for AI Feature Extraction Stage
 *
 * Following TDD approach - these tests MUST FAIL before implementation.
 *
 * This stage uses LangChain OpenAI integration with GPT-4o-mini for semantic feature extraction
 * with JSON schema validation and batch processing support.
 */

import { aiFeatureExtractionStage, AIFeatureExtractionConfig } from '../../src/stages/ai-feature-extraction';
import { EmailMessage, ClassificationSession } from '../../src/types';

// Mock OpenAI client for testing
const mockCreate = jest.fn();
jest.mock('openai', () => ({
  OpenAI: jest.fn().mockImplementation(() => ({
    chat: {
      completions: {
        create: mockCreate,
      },
    },
  })),
}));

describe('AI Feature Extraction Stage', () => {
  const mockConfig: AIFeatureExtractionConfig = {
    openai: {
      apiKey: 'test-api-key',
      model: 'gpt-4o-mini',
      temperature: 0.0,
      responseFormat: 'json_schema',
    },
    prompts: {
      systemPrompt: [
        'You are an expert email analyst that ONLY reports evidence that exists in the actual email content.',
        'Your primary directive is to ground all analysis in exact phrases and keywords from the provided email text.',
      ],
      userPrompt: [
        'Analyze this email and extract ONLY evidence that literally exists in the email text.',
        'You must quote exact phrases and identify actual keywords.',
        '',
        'Email Content:',
        'From: {email.from}',
        'Subject: {email.subject}',
        'Body: {email.body}',
        '',
        'Existing Rule-Based Analysis:',
        '',
        '```xml',
        '<candidate_categories>',
        '{candidateCategories}',
        '</candidate_categories>',
        '',
        '<detected_attributes>',
        '{detectedAttributes}',
        '</detected_attributes>',
        '```',
      ],
    },
    featureExtractionSchema: {
      name: 'feature_extraction',
      description: 'Extract semantic features and category enhancements from email content',
      schema: {
        type: 'object',
        properties: {
          semantic_intent: {
            type: 'object',
            properties: {
              primary_purpose: { type: 'string', enum: ['notification', 'request', 'update', 'alert'] },
              action_required: { type: 'string', enum: ['none', 'view', 'respond', 'complete'] },
              urgency_level: { type: 'string', enum: ['none', 'low', 'medium', 'high'] },
            },
            required: ['primary_purpose', 'action_required', 'urgency_level'],
          },
          category_enhancements: {
            type: 'object',
            properties: {
              financial: {
                type: 'object',
                properties: {
                  applies: { type: 'boolean' },
                  confidence_boost: { type: 'number', minimum: -1, maximum: 1 },
                  evidence: {
                    type: 'object',
                    properties: {
                      quoted_phrases: { type: 'array', items: { type: 'string' } },
                      keywords: { type: 'array', items: { type: 'string' } },
                      reasoning: { type: 'string' },
                    },
                    required: ['quoted_phrases', 'keywords', 'reasoning'],
                  },
                },
                required: ['applies', 'confidence_boost', 'evidence'],
              },
              actionable: {
                type: 'object',
                properties: {
                  applies: { type: 'boolean' },
                  confidence_boost: { type: 'number', minimum: -1, maximum: 1 },
                  evidence: {
                    type: 'object',
                    properties: {
                      quoted_phrases: { type: 'array', items: { type: 'string' } },
                      keywords: { type: 'array', items: { type: 'string' } },
                      reasoning: { type: 'string' },
                    },
                    required: ['quoted_phrases', 'keywords', 'reasoning'],
                  },
                },
                required: ['applies', 'confidence_boost', 'evidence'],
              },
            },
          },
        },
        required: ['semantic_intent', 'category_enhancements'],
      },
      strict: true,
    },
    retryPolicy: {
      maxRetries: 3,
      backoffMs: 1000,
    },
  };

  const mockEmail: EmailMessage = {
    id: 'test-123',
    threadId: 'thread-123',
    gmailLabels: [],
    payload: {
      mimeType: 'text/plain',
      headers: [
        { name: 'Subject', value: 'Your monthly statement is ready' },
        { name: 'From', value: 'Bank of Example <statements@bank.example.com>' },
        { name: 'To', value: 'User <user@example.com>' },
      ],
    },
    subject: 'Your monthly statement is ready',
    from: {
      email: 'statements@bank.example.com',
      name: 'Bank of Example',
      raw: 'Bank of Example <statements@bank.example.com>',
    },
    to: [{ email: 'user@example.com', name: 'User', raw: 'User <user@example.com>' }],
    bodyPlain:
      'Your monthly statement for account ending in 1234 is now available. Please log in to view your statement and recent transactions.',
    bodyHtml:
      '<p>Your monthly statement for account ending in 1234 is now available. Please log in to view your statement and recent transactions.</p>',
    date: new Date('2024-01-01T10:00:00Z'),
    isProcessed: false,
    processingPriority: 1,
  };

  const mockSession: ClassificationSession = {
    id: 'session-123',
    startedAt: new Date('2024-01-01T10:00:00Z'),
    emailCount: 1,
    successCount: 0,
    errorCount: 0,
    processingMode: 'parallel',
    batchSize: 1,
    performanceMetrics: {
      totalDurationMs: 0,
      avgEmailDurationMs: 0,
      parallelStagesCount: 0,
      databaseBatchOps: 0,
    },
    configVersion: 'test-version',
    configSnapshot: {},
    errors: [],
    warnings: [],
  };

  const mockCandidateCategories = {
    financial: { score: 12.5, confidence: 85, decision: 'selected' },
    actionable: { score: 8.0, confidence: 70, decision: 'candidate' },
  };

  const mockDetectedAttributes = {
    urgency: 'medium',
    domains: ['bank.example.com'],
    structuralPatterns: ['statement_notification'],
  };

  beforeEach(() => {
    jest.clearAllMocks();
    mockCreate.mockReset();
  });

  describe('OpenAI Integration', () => {
    it('should call OpenAI with correct parameters', async () => {
      const mockOpenAIResponse = {
        choices: [
          {
            message: {
              content: JSON.stringify({
                semantic_intent: {
                  primary_purpose: 'notification',
                  action_required: 'view',
                  urgency_level: 'medium',
                },
                category_enhancements: {
                  financial: {
                    applies: true,
                    confidence_boost: 0.8,
                    evidence: {
                      quoted_phrases: ['monthly statement', 'account ending in 1234'],
                      keywords: ['statement', 'account', 'transactions'],
                      reasoning: 'Email contains explicit financial account references and statement language',
                    },
                  },
                  actionable: {
                    applies: true,
                    confidence_boost: 0.3,
                    evidence: {
                      quoted_phrases: ['Please log in to view'],
                      keywords: ['log', 'view'],
                      reasoning: 'Email requests user action to view statement',
                    },
                  },
                },
              }),
            },
          },
        ],
        usage: { total_tokens: 250 },
      };

      mockCreate.mockResolvedValueOnce(mockOpenAIResponse);

      const result = await aiFeatureExtractionStage(
        mockEmail,
        mockSession,
        mockCandidateCategories,
        mockDetectedAttributes,
        mockConfig
      );

      expect(mockCreate).toHaveBeenCalledWith({
        model: 'gpt-4o-mini',
        temperature: 0.0,
        response_format: {
          type: 'json_schema',
          json_schema: {
            name: 'feature_extraction',
            description: 'Extract semantic features and category enhancements from email content',
            schema: mockConfig.featureExtractionSchema.schema,
            strict: true,
          },
        },
        messages: [
          {
            role: 'system',
            content: mockConfig.prompts.systemPrompt.join('\n'),
          },
          {
            role: 'user',
            content: expect.stringContaining('Your monthly statement is ready'),
          },
        ],
      });

      expect(result.featureExtraction).toBeDefined();
      expect(result.featureExtraction.semantic_intent.primary_purpose).toBe('notification');
    });

    it('should support backward compatibility with json_object mode', async () => {
      const legacyConfig = {
        ...mockConfig,
        openai: {
          ...mockConfig.openai,
          responseFormat: 'json_object' as const,
        },
        featureExtractionSchema: {
          ...mockConfig.featureExtractionSchema,
          schema: mockConfig.featureExtractionSchema.schema, // Legacy format
        },
      };

      const mockOpenAIResponse = {
        choices: [
          {
            message: {
              content: JSON.stringify({
                semantic_intent: {
                  primary_purpose: 'notification',
                  action_required: 'view',
                  urgency_level: 'medium',
                },
                category_enhancements: {
                  financial: {
                    applies: true,
                    confidence_boost: 0.8,
                    evidence: {
                      quoted_phrases: ['monthly statement'],
                      keywords: ['statement'],
                      reasoning: 'Contains financial statement language',
                    },
                  },
                },
              }),
            },
          },
        ],
        usage: { total_tokens: 200 },
      };

      mockCreate.mockResolvedValueOnce(mockOpenAIResponse);

      const result = await aiFeatureExtractionStage(
        mockEmail,
        mockSession,
        mockCandidateCategories,
        mockDetectedAttributes,
        legacyConfig
      );

      expect(mockCreate).toHaveBeenCalledWith({
        model: 'gpt-4o-mini',
        temperature: 0.0,
        response_format: { type: 'json_object' },
        messages: [
          {
            role: 'system',
            content: legacyConfig.prompts.systemPrompt.join('\n'),
          },
          {
            role: 'user',
            content: expect.stringContaining('Your monthly statement is ready'),
          },
        ],
      });

      expect(result.featureExtraction).toBeDefined();
      expect(result.validationPassed).toBe(true);
    });

    it('should handle OpenAI API errors with retry policy', async () => {
      mockCreate
        .mockRejectedValueOnce(new Error('Rate limit exceeded'))
        .mockRejectedValueOnce(new Error('Temporary server error'))
        .mockResolvedValueOnce({
          choices: [
            {
              message: {
                content: JSON.stringify({
                  semantic_intent: {
                    primary_purpose: 'notification',
                    action_required: 'view',
                    urgency_level: 'medium',
                  },
                  category_enhancements: {
                    financial: {
                      applies: true,
                      confidence_boost: 0.5,
                      evidence: {
                        quoted_phrases: ['statement'],
                        keywords: ['statement'],
                        reasoning: 'Contains statement reference',
                      },
                    },
                  },
                }),
              },
            },
          ],
          usage: { total_tokens: 150 },
        });

      const result = await aiFeatureExtractionStage(
        mockEmail,
        mockSession,
        mockCandidateCategories,
        mockDetectedAttributes,
        mockConfig
      );

      expect(mockCreate).toHaveBeenCalledTimes(3);
      expect(result.featureExtraction).toBeDefined();
      expect(result.retryCount).toBe(2);
    });

    it('should fail after max retries are exhausted', async () => {
      mockCreate.mockRejectedValue(new Error('Persistent API error'));

      await expect(
        aiFeatureExtractionStage(mockEmail, mockSession, mockCandidateCategories, mockDetectedAttributes, mockConfig)
      ).rejects.toThrow('AI feature extraction failed after 3 retries');

      expect(mockCreate).toHaveBeenCalledTimes(3);
    });
  });

  describe('JSON Schema Validation', () => {
    it('should validate successful OpenAI response against schema', async () => {
      const validResponse = {
        semantic_intent: {
          primary_purpose: 'notification',
          action_required: 'view',
          urgency_level: 'medium',
        },
        category_enhancements: {
          financial: {
            applies: true,
            confidence_boost: 0.7,
            evidence: {
              quoted_phrases: ['monthly statement'],
              keywords: ['statement'],
              reasoning: 'Contains financial statement language',
            },
          },
          actionable: {
            applies: false,
            confidence_boost: 0,
            evidence: {
              quoted_phrases: [],
              keywords: [],
              reasoning: 'No evidence found',
            },
          },
        },
      };

      mockCreate.mockResolvedValueOnce({
        choices: [{ message: { content: JSON.stringify(validResponse) } }],
        usage: { total_tokens: 200 },
      });

      const result = await aiFeatureExtractionStage(
        mockEmail,
        mockSession,
        mockCandidateCategories,
        mockDetectedAttributes,
        mockConfig
      );

      expect(result.featureExtraction).toEqual(validResponse);
      expect(result.validationPassed).toBe(true);
      expect(result.validationErrors).toHaveLength(0);
    });

    it('should handle invalid JSON response from OpenAI', async () => {
      mockCreate.mockResolvedValue({
        choices: [{ message: { content: 'Invalid JSON response {truncated...' } }],
        usage: { total_tokens: 50 },
      });

      await expect(
        aiFeatureExtractionStage(mockEmail, mockSession, mockCandidateCategories, mockDetectedAttributes, mockConfig)
      ).rejects.toThrow('Invalid JSON response from OpenAI');
    });

    it('should handle schema validation failures in legacy json_object mode', async () => {
      const legacyConfig = {
        ...mockConfig,
        openai: {
          ...mockConfig.openai,
          responseFormat: 'json_object' as const,
        },
      };

      const invalidResponse = {
        semantic_intent: {
          primary_purpose: 'invalid_purpose', // Not in enum
          action_required: 'view',
          urgency_level: 'medium',
        },
        category_enhancements: {
          financial: {
            applies: true,
            confidence_boost: 2.0, // Outside allowed range
            evidence: {
              // Missing required fields
            },
          },
        },
      };

      mockCreate.mockResolvedValue({
        choices: [{ message: { content: JSON.stringify(invalidResponse) } }],
        usage: { total_tokens: 150 },
      });

      await expect(
        aiFeatureExtractionStage(mockEmail, mockSession, mockCandidateCategories, mockDetectedAttributes, legacyConfig)
      ).rejects.toThrow('Schema validation failed');
    });
  });

  describe('Enhanced Template System', () => {
    it('should handle complex nested objects in templates', async () => {
      const complexCandidateCategories = {
        financial: {
          score: 15.75,
          confidence: 92,
          decision: 'selected',
          breakdown: {
            hardAssertions: 8.0,
            strongIndicators: 4.5,
            ruleScoring: 3.25,
          },
        },
        actionable: {
          score: 6.25,
          confidence: 68,
          decision: 'candidate',
          breakdown: {
            hardAssertions: 0.0,
            strongIndicators: 2.0,
            ruleScoring: 4.25,
          },
        },
      };

      const complexAttributes = {
        urgency: 'medium',
        domains: ['bank.example.com', 'statement.bank.example.com'],
        structuralPatterns: ['statement_notification', 'account_update'],
        derivedFlags: {
          hasFinancialTerms: true,
          requiresUserAction: true,
          isPersonalCommunication: false,
        },
      };

      mockCreate.mockResolvedValueOnce({
        choices: [
          {
            message: {
              content: JSON.stringify({
                semantic_intent: {
                  primary_purpose: 'notification',
                  action_required: 'view',
                  urgency_level: 'medium',
                },
                category_enhancements: {},
              }),
            },
          },
        ],
        usage: { total_tokens: 200 },
      });

      await aiFeatureExtractionStage(mockEmail, mockSession, complexCandidateCategories, complexAttributes, mockConfig);

      const calledArgs = mockCreate.mock.calls[0][0];
      const userMessage = calledArgs.messages[1].content;

      // Verify complex object interpolation with XML structure
      expect(userMessage).toContain('<candidate_categories>');
      expect(userMessage).toContain('</candidate_categories>');
      expect(userMessage).toContain('breakdown');
      expect(userMessage).toContain('hardAssertions');
      expect(userMessage).toContain('strongIndicators');

      expect(userMessage).toContain('<detected_attributes>');
      expect(userMessage).toContain('</detected_attributes>');
      expect(userMessage).toContain('domains');
      expect(userMessage).toContain('bank.example.com');
      expect(userMessage).toContain('derivedFlags');
      expect(userMessage).toContain('hasFinancialTerms');

      // Verify formatted JSON (should be pretty-printed with indentation)
      expect(userMessage).toContain('financial'); // JSON key
      expect(userMessage).toContain('15.75'); // Score value
